/*
  Global design system based on the provided HVAC layout
  - Playful, friendly branding with bold pill CTAs
  - Clean, flat UI with strong cyan header band and red CTA
*/

:root {
  /* Color palette */
  --color-primary-400: #00ddf5; /* bright cyan header band */
  --color-primary-500: #00c2de; /* slightly deeper cyan */

  --color-secondary-red: #ff3b30; /* red CTA */
  --color-secondary-yellow: #ffd447;

  --color-neutral-0: #ffffff;
  --color-neutral-50: #f7f8fa; /* light section bg */
  --color-neutral-100: #e5edf4; /* light borders, snowflakes */
  --color-neutral-900: #111111;
  --color-neutral-700: #555555;

  --color-semantic-success: #23b26b;
  --color-semantic-error: #e53935;
  --color-semantic-warning: #ffb020;
  --color-semantic-info: #00a4d8;

  /* Typography */
  --font-heading: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;

  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px baseline) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  /* Radii */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-pill: 999px;

  /* Shadows */
  --shadow-soft: 0 4px 12px rgba(0, 0, 0, 0.04);
  --shadow-strong: 0 6px 18px rgba(0, 0, 0, 0.12);

  /* Layout */
  --max-width: 1200px;
}

/* CSS Reset / Base */
*, *::before, *::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-900);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus-visible {
  text-decoration: underline;
}

p {
  margin: 0 0 var(--space-sm);
}

h1, h2, h3, h4, h5, h6 {
  margin: 0 0 var(--space-sm);
  font-family: var(--font-heading);
  font-weight: 700;
  line-height: var(--line-height-tight);
  color: var(--color-neutral-900);
}

.site-main {
  min-height: 50vh;
  padding: var(--space-xl) 0;
  background-color: var(--color-neutral-0);
}

.container {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 var(--space-md);
}

/* Top announcement bar */
.top-bar {
  background-color: var(--color-primary-400);
  color: var(--color-neutral-900);
  font-family: var(--font-body);
}

.top-bar__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-sm) 0;
  gap: var(--space-md);
}

.top-bar__message {
  font-size: 15px;
  font-weight: 500;
}

.top-bar__pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 28px;
  border-radius: var(--radius-pill);
  border: 2px solid var(--color-neutral-900);
  background-color: var(--color-neutral-0);
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  box-shadow: var(--shadow-soft);
}

/* Header main area */
.site-header {
  background-color: var(--color-neutral-0);
}

.header-main {
  border-bottom: 1px solid var(--color-neutral-100);
}

.header-main__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-md) 0;
  gap: var(--space-lg);
}

/* Brand / logo area */
.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
}

.brand__logo-mark {
  width: 150px;
  height: 60px;
  border-radius: var(--radius-md);
  background: linear-gradient(135deg, var(--color-primary-400), var(--color-primary-500));
  box-shadow: var(--shadow-strong);
}

.brand__text {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.brand__name {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 22px;
}

.brand__tagline {
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-neutral-700);
}

/* Primary navigation */
.primary-nav {
  flex: 1;
}

.primary-nav__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 28px;
}

.primary-nav__item {
  display: flex;
}

.primary-nav__link {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 6px 0;
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.09em;
  color: var(--color-neutral-900);
  text-decoration: none;
}

.primary-nav__link::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -4px;
  width: 0;
  height: 2px;
  background-color: var(--color-primary-500);
  transition: width 0.2s ease-out;
}

.primary-nav__link:hover::after,
.primary-nav__link:focus-visible::after {
  width: 100%;
}

.primary-nav__link.is-active {
  color: var(--color-primary-500);
}

.primary-nav__link.is-active::after {
  width: 100%;
}

/* Red pill CTA for Schedule Service (matches Subscriptions style) */
.primary-nav__item--cta {
  margin-left: 8px;
}

.primary-nav__link--cta {
  padding: 10px 26px;
  border-radius: var(--radius-pill);
  background-color: var(--color-secondary-red);
  color: var(--color-neutral-0);
  border: 2px solid var(--color-secondary-red);
  box-shadow: var(--shadow-soft);
}

.primary-nav__link--cta::after {
  display: none; /* no underline bar on pill CTA */
}

.primary-nav__link--cta:hover,
.primary-nav__link--cta:focus-visible {
  text-decoration: none;
  background-color: #e23328; /* slightly darker on hover */
  border-color: #e23328;
}

/* Footer styling */
.site-footer {
  margin-top: var(--space-xl);
  background-color: var(--color-neutral-50);
  border-top: 1px solid var(--color-neutral-100);
}

.site-footer__top {
  padding: var(--space-xl) 0;
}

.site-footer__inner {
  display: grid;
  grid-template-columns: minmax(0, 2fr) minmax(0, 1.5fr) minmax(0, 2fr);
  gap: var(--space-xl);
}

.site-footer__brand {
  max-width: 360px;
}

.footer-logo {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  margin-bottom: var(--space-sm);
}

.footer-logo__mark {
  width: 80px;
  height: 40px;
  border-radius: var(--radius-md);
  background: linear-gradient(135deg, var(--color-primary-400), var(--color-primary-500));
  box-shadow: var(--shadow-soft);
}

.footer-logo__text {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.footer-logo__name {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 18px;
}

.footer-logo__tagline {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-neutral-700);
}

.site-footer__blurb {
  font-size: 14px;
  color: var(--color-neutral-700);
  line-height: var(--line-height-relaxed);
}

.site-footer__heading {
  font-size: 14px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  margin-bottom: var(--space-sm);
}

.site-footer__nav {
  min-width: 180px;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-links__item + .footer-links__item {
  margin-top: 6px;
}

.footer-links__link {
  font-size: 14px;
  color: var(--color-neutral-700);
}

.footer-links__link:hover,
.footer-links__link:focus-visible {
  color: var(--color-primary-500);
  text-decoration: none;
}

.site-footer__details {
  max-width: 320px;
}

.site-footer__text {
  font-size: 14px;
  color: var(--color-neutral-700);
  line-height: var(--line-height-relaxed);
}

.site-footer__text--muted {
  margin-top: var(--space-xs);
  font-size: 13px;
  color: #777777;
}

.site-footer__bottom {
  border-top: 1px solid var(--color-neutral-100);
  background-color: #f1f3f7;
}

.site-footer__bottom-inner {
  padding: var(--space-sm) 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.site-footer__copy {
  margin: 0;
  font-size: 13px;
  color: var(--color-neutral-700);
}

/* Utility styles for future site-wide usage (cards, forms, etc.) */
.card {
  background-color: var(--color-neutral-0);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-soft);
  padding: var(--space-md);
}

.form-group {
  margin-bottom: var(--space-md);
}

.form-label {
  display: block;
  margin-bottom: 6px;
  font-size: 14px;
  font-weight: 600;
}

.form-control {
  width: 100%;
  padding: 10px 12px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--color-neutral-100);
  font-family: var(--font-body);
  font-size: 15px;
}

.form-control:focus {
  outline: none;
  border-color: var(--color-primary-500);
  box-shadow: 0 0 0 1px rgba(0, 162, 222, 0.2);
}

.form-error {
  margin-top: 4px;
  font-size: 12px;
  color: var(--color-semantic-error);
}

/* Responsive adjustments */
@media (max-width: 960px) {
  .header-main__inner {
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--space-md);
  }

  .primary-nav__list {
    flex-wrap: wrap;
    justify-content: center;
    gap: 18px;
  }

  .top-bar__inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .top-bar__pill {
    align-self: stretch;
    justify-content: center;
  }

  .site-footer__inner {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 640px) {
  .container {
    padding: 0 var(--space-sm);
  }

  .top-bar__inner {
    align-items: flex-start;
  }

  .top-bar__message {
    font-size: 14px;
  }

  .primary-nav__list {
    flex-direction: column;
    align-items: center;
  }

  .site-footer__inner {
    grid-template-columns: 1fr;
  }

  .site-footer__brand,
  .site-footer__nav,
  .site-footer__details {
    max-width: none;
  }
}
